module garage_door (
	input clk,
	input resetn,
	input button,
	output reg open);

	parameter CLOSED=0, OPEN=1;
	reg obf_state, next_state;

	always @(posedge clk) begin
		if (~resetn) obf_state <= CLOSED;
		else obf_state <= next_state;
	end

	always_comb begin
		case (obf_state)
			CLOSED: next_state = button ? OPEN : CLOSED;
			OPEN: next_state = button ? CLOSED : OPEN;
			default: next_state = CLOSED;
		endcase
	end

	always @(obf_state) begin
		case (obf_state)
			OPEN: open = 1;
			default: open = 0;
		endcase
	end
endmodule
